    {
      "name": "Quizlet",
      "details": "Offers flashcards, practice tests, and AI-assisted study guides to students worldwide. Competes directly on quiz generation and study aids.",
      "businessModel": "Freemium subscription (Quizlet Plus) and advertising."
    },
    {
      "name": "Anki",
      "details": "Offers open-source spaced repetition flashcards for students and language learners. Competes on personalized retrieval practice.",
      "businessModel": "Free desktop and Android apps, paid iOS app purchase."
    },
    {
      "name": "Shovel App",
      "details": "Offers a detailed study planner and calendar integration for college students. Competes on time management and study scheduling.",
      "businessModel": "Subscription-based (monthly/annual)."
    },
    {
      "name": "Socratic by Google",
      "details": "Offers AI-powered explanations and study resources for high school and university students. Competes on AI-driven learning support.",
      "businessModel": "Free (funded by Google's ecosystem)."
    }
